def _as_bool(value, default=False):
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    raw = str(value or '').strip().lower()
    if raw in ('1', 'true', 'yes', 'y', 'on', 'enabled'):
        return True
    if raw in ('0', 'false', 'no', 'n', 'off', 'disabled'):
        return False
    return bool(default)


def _as_int(value, default=0, minimum=None, maximum=None):
    try:
        parsed = int(str(value).strip())
    except Exception:
        parsed = int(default)
    if minimum is not None:
        parsed = max(int(minimum), parsed)
    if maximum is not None:
        parsed = min(int(maximum), parsed)
    return parsed


def _canonical_feature_key(key):
    raw = str(key or '').strip().lower()
    if not raw:
        return ''
    return FEATURE_KEY_ALIASES.get(raw, raw)


def _normalize_feature_flags(raw, base=None):
    out = dict(base or FEATURE_FLAG_DEFAULTS)
    if not isinstance(raw, dict):
        return out
    for key, value in raw.items():
        canonical = _canonical_feature_key(key)
        if canonical in FEATURE_FLAG_DEFAULTS:
            out[canonical] = _as_bool(value, out.get(canonical))
    return out


def _load_feature_flags():
    try:
        if os.path.exists(FEATURE_FLAGS_PATH):
            with open(FEATURE_FLAGS_PATH, 'r') as f:
                data = json.load(f)
            if isinstance(data, dict):
                source = data.get('features') if isinstance(data.get('features'), dict) else data
                return _normalize_feature_flags(source, FEATURE_FLAG_DEFAULTS)
    except Exception:
        pass
    return dict(FEATURE_FLAG_DEFAULTS)


def _save_feature_flags(flags):
    normalized = _normalize_feature_flags(flags, FEATURE_FLAG_DEFAULTS)
    os.makedirs(os.path.dirname(FEATURE_FLAGS_PATH) or '.', exist_ok=True)
    with open(FEATURE_FLAGS_PATH, 'w') as f:
        json.dump({
            'features': normalized,
            'updated_at': datetime.now().isoformat()
        }, f, indent=2)
    return normalized


def _normalize_role_mappings(raw):
    items = raw if isinstance(raw, list) else []
    out = []
    seen = set()
    for item in items:
        if not isinstance(item, dict):
            continue
        account_id = re.sub(r'[^0-9]', '', str(item.get('account_id') or '').strip())
        role_arn = str(item.get('role_arn') or '').strip()
        account_name = str(item.get('account_name') or item.get('label') or '').strip()
        if not account_id or not role_arn:
            continue
        sig = f'{account_id}:{role_arn}'
        if sig in seen:
            continue
        seen.add(sig)
        out.append({
            'account_id': account_id,
            'role_arn': role_arn,
            'account_name': account_name,
            'label': account_name,
        })
    return out


def _normalize_db_proxy_mappings(raw):
    items = raw if isinstance(raw, list) else []
    out = []
    seen = set()
    for item in items:
        if not isinstance(item, dict):
            continue
        account_id = re.sub(r'[^0-9]', '', str(item.get('account_id') or '').strip())
        proxy_host = str(item.get('proxy_host') or item.get('host') or '').strip()
        account_name = str(item.get('account_name') or item.get('label') or '').strip()
        port_raw = str(item.get('proxy_port') or item.get('port') or '').strip()
        try:
            proxy_port = int(port_raw) if port_raw else 3306
        except Exception:
            proxy_port = 3306
        if not account_id or not proxy_host:
            continue
        sig = f'{account_id}:{proxy_host.lower()}:{proxy_port}'
        if sig in seen:
            continue
        seen.add(sig)
        out.append({
            'account_id': account_id,
            'account_name': account_name,
            'label': account_name,
            'proxy_host': proxy_host,
            'proxy_port': proxy_port,
        })
    return out


def _normalize_vault_connection_name_map(raw):
    items = raw if isinstance(raw, dict) else {}
    out = {}
    for key, value in items.items():
        map_key = str(key or '').strip().lower()
        map_value = str(value or '').strip()
        if not map_key or not map_value:
            continue
        out[map_key] = map_value
    return out


